import React, { useEffect, useState } from "react";
import { FileText, Star, Check, Calendar, Globe, Bookmark } from "lucide-react";
import api from "../api"; // Adjust import based on your setup

const Dashboard = ({ token, getStatusColor }) => {
  const [metrics, setMetrics] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Replace with your real API call
    const fetchMetrics = async () => {
      try {
        const res = await api.get("/dashboard/metrics", {
          headers: { Authorization: `Bearer ${token}` }
        });
        setMetrics(res.data);
      } catch (e) {
        setMetrics(null);
      }
      setLoading(false);
    };
    fetchMetrics();
  }, [token]);

  if (loading) return <div className="p-6">Loading dashboard...</div>;
  if (!metrics) return <div className="p-6 text-red-500">Error loading dashboard data.</div>;

  return (
    <div className="p-6 space-y-6">
      {/* Metric Cards */}
      <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
        <MetricCard label="Total Articles" value={metrics.total_articles} icon={<FileText className="w-8 h-8 text-blue-500" />} />
        <MetricCard label="Paid Articles" value={metrics.total_paid_articles} icon={<Bookmark className="w-8 h-8 text-indigo-500" />} />
        <MetricCard label="Shortlisted" value={metrics.shortlisted} icon={<Star className="w-8 h-8 text-yellow-500" />} />
        <MetricCard label="Final Selection" value={metrics.final} icon={<Check className="w-8 h-8 text-green-500" />} />
        <MetricCard label="Next Deck Due" value="July 31" icon={<Calendar className="w-8 h-8 text-purple-500" />} />
      </div>

      {/* Recent Activity */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <ActivityPanel
          title="Recent Main Articles"
          items={metrics.latest_articles}
          getStatusColor={getStatusColor}
        />
        <ActivityPanel
          title="Recent Paid Search Results"
          items={metrics.latest_paid}
          icon={<Bookmark className="inline w-4 h-4 text-indigo-500" />}
        />
      </div>
    </div>
  );
};

// Sub-components

const MetricCard = ({ label, value, icon }) => (
  <div className="bg-white rounded-lg shadow p-6 flex flex-col justify-between">
    <div className="flex items-center justify-between">
      <div>
        <p className="text-sm text-gray-600">{label}</p>
        <p className="text-2xl font-bold text-gray-900">{value}</p>
      </div>
      {icon}
    </div>
  </div>
);

const ActivityPanel = ({ title, items, getStatusColor, icon }) => (
  <div className="bg-white rounded-lg shadow p-6">
    <h3 className="text-lg font-semibold mb-4">{title}</h3>
    <div className="space-y-3">
      {(!items || items.length === 0) && (
        <div className="text-sm text-gray-500">No activity yet.</div>
      )}
      {items && items.map((item, idx) => (
        <div key={idx} className="flex items-center justify-between py-2 border-b last:border-0">
          <div className="flex-1">
            <p className="font-medium text-gray-900 flex items-center gap-2">
              {icon} {item.title}
            </p>
            <p className="text-sm text-gray-500">{item.source} • {item.date && item.date.substring(0, 10)}</p>
          </div>
          {item.status &&
            <span className={`px-3 py-1 rounded-full text-xs font-medium ${getStatusColor(item.status)}`}>
              {item.status}
            </span>
          }
          {item.score !== undefined && (
            <span className="ml-2 text-xs text-indigo-600 font-bold">Score: {item.score}</span>
          )}
        </div>
      ))}
    </div>
  </div>
);

export default Dashboard;
